class SignalProcessing():
    """
    Class signal_processing performs preprocessing including filtering and artifact removal

    input: Xin
        Xin[:,0] = timestamp
        Xin[:,1] = sensor value

    input: params
        params = {
        'window_mva': ...,
        'window_bl': ...,
        'window_art_mva': ...,
        'window_art_bl': ...,
        'window_smooth_output': ...,
        'th_prepro': ...
        }            
    """

    def __init__(self, Xin=None, params=None):
        if Xin is not None:
            self.time = Xin[:, 0].reshape(-1)
            self.val = Xin[:, 1].reshape(-1)

        if params is not None:
            self.window_mva = params["window_mva"]
            self.window_mva_activeness = params['window_mva_activeness']
            self.window_bl = params["window_bl"]
            self.window_art_mva = params["window_art_mva"]
            self.window_art_bl = params["window_art_bl"]
            self.window_smooth_output = params["window_smooth_output"]
            self.th = params["th_prepro"]

        self.mva_time = []  # moving average
        self.mva_val = []

        self.bl_val = []  # baseline
        self.bl_time = []

        self.blrm_val = []  # baseline removal
        self.blrm_time = []

        self.art_val = []  # artifact
        self.art_time = []

        self.artbl_val = []  # artifact baseline
        self.artbl_time = []

        self.output = []  # output

    def moving_average(self, time, val, window_size):
        """
        If window_size==0: returns input
        """
        if window_size == 0:
            mva_time = time
            mva_val = val
        else:
            temp = pd.Series(val)
            temp_mva = temp.rolling(window=window_size, center=True).mean()
            mva_val = temp_mva[int(math.floor(window_size/2)):(len(temp)-int(math.floor(window_size/2)))]
            mva_val = np.array(mva_val)

            mva_time = time[int(math.floor(window_size/2)):(len(time)-int(math.floor(window_size/2)))]
        return mva_time, mva_val

    def baseline(self, time, val, window_size):
        """
        If window_size==0: returns input
        """
        if window_size == 0:
            bl_time = time
            bl_val = val
        else:
            temp = pd.Series(val)
            temp_bl = temp.rolling(window=window_size, center=True).median()  # median filter
            bl_val = temp_bl[int(math.floor(window_size/2)):(len(temp)-int(math.floor(window_size/2)))]
            bl_val = np.array(bl_val)

            bl_time = time[int(math.floor(window_size/2)):(len(time)-int(math.floor(window_size/2)))]
        return bl_time, bl_val

    # Baseline removal followed by zero padding front and back
    """
    def baseline_removal(self, signal_time, signal_val, baseline_time, baseline_val):
        signal_time = list(signal_time)
        baseline_time = list(baseline_time)
        blrm_val = signal_val[signal_time.index(baseline_time[0]):signal_time.index(baseline_time[-1])+1] - baseline_val
        output1 = np.pad(blrm_val, (555, 555), 'constant', constant_values=0)  # 0 padding for KT, padding
                                                                               # 720 for data length of 40s to get
                                                                               # exactly 1 result and no need to take median
                                                                               # 555 for data length of 60s
        blrm_val = output1
        time_end = max(baseline_time)
        time_ramp = baseline_time[-1] - baseline_time[-2]
        for i in range(2000):
            append_val = time_end + (i + 1) * time_ramp
            baseline_time = np.append(baseline_time, append_val)   # 0 padding for RR calculation
        return baseline_time, blrm_val

    """
    # Normal baseline removal

    def baseline_removal(self, signal_time, signal_val, baseline_time, baseline_val):
        signal_time = list(signal_time)
        baseline_time = list(baseline_time)
        blrm_val = signal_val[signal_time.index(baseline_time[0]):signal_time.index(
            baseline_time[-1]) + 1] - baseline_val
        return baseline_time, blrm_val

    def artifact(self, time, val, window_size, mva_filt=True):
        output = val[1:len(val)-1]**2 - val[0:len(val)-2] * val[2:len(val)]
        time = time[1:len(val)-1]

        output = np.abs(output)
        if mva_filt == True:  # smoothen the output (optional)
            time, output = self.moving_average(time, output, window_size)
        return time, output

    def artifact_removal(self, signal_time, signal_val, art_time, art_val, artbl_time, artbl_val, th, window_size, mva_filt=True):
        signal_time = list(signal_time)
        art_time = list(art_time)
        signal_val = signal_val[signal_time.index(artbl_time[0]):signal_time.index(artbl_time[-1])+1]
        art_val = art_val[art_time.index(artbl_time[0]):art_time.index(artbl_time[-1])+1]

        output = signal_val[art_val < th*artbl_val]
        if mva_filt == True:  # smoothen the output (optional)
            time = np.arange(0, len(output))
            _, output = self.moving_average(time, output, window_size)
        return output

    def run_signal_processing(self):
        """
        perform signal processing
        """
        self.mva_time,  self.mva_val = self.moving_average(self.time, self.val, self.window_mva)
        self.bl_time,   self.bl_val = self.baseline(self.mva_time, self.mva_val, self.window_bl)
        self.blrm_time, self.blrm_val = self.baseline_removal(self.mva_time, self.mva_val, self.bl_time, self.bl_val)
        self.art_time,   self.art_val = self.artifact(self.blrm_time, self.blrm_val, self.window_art_mva)
        self.artbl_time, self.artbl_val = self.baseline(self.art_time, self.art_val, self.window_art_bl)

    def run_signal_processing_for_activity(self):
        self.mva_time,  self.mva_val = self.moving_average(self.time, self.val, self.window_mva_activeness)
        self.art_time,   self.art_val = self.artifact(self.mva_time, self.mva_val, self.window_art_mva)



class signal_processing():
    def __init__(self, Xin=None, params=None):
        if Xin is not None:
            self.time = Xin[:, 0].reshape(-1)
            self.val = Xin[:, 1].reshape(-1)

        if params is not None:
            self.window_mva = params["window_mva"]
            self.window_bl = params["window_bl"]
            self.window_art_mva = params["window_art_mva"]
            self.window_art_bl = params["window_art_bl"]
            self.window_smooth_output = params["window_smooth_output"]
            self.th = params["th_prepro"]

        self.mva_time = []  # moving average
        self.mva_val = []

        self.bl_val = []  # baseline
        self.bl_time = []

        self.blrm_val = []  # baseline removal
        self.blrm_time = []

        self.art_val = []  # artifact
        self.art_time = []

        self.artbl_val = []  # artifact baseline
        self.artbl_time = []

        self.output = []  # output

    def moving_average(self, time, val, window_size):
        """
        If window_size==0: returns input
        """
        if window_size == 0:
            mva_time = time
            mva_val = val
        else:
            temp = pd.Series(val)
            temp_mva = temp.rolling(window=window_size, center=True).mean()
            mva_val = temp_mva[int(math.floor(window_size/2)):(len(temp)-int(math.floor(window_size/2)))]
            mva_val = np.array(mva_val)

            mva_time = time[int(math.floor(window_size/2)):(len(time)-int(math.floor(window_size/2)))]
        return mva_time, mva_val

    def baseline(self, time, val, window_size):
        """
        If window_size==0: returns input
        """
        if window_size == 0:
            bl_time = time
            bl_val = val
        else:
            temp = pd.Series(val)
            temp_bl = temp.rolling(window=window_size, center=True).median()  # median filter
            bl_val = temp_bl[int(math.floor(window_size/2)):(len(temp)-int(math.floor(window_size/2)))]
            bl_val = np.array(bl_val)

            bl_time = time[int(math.floor(window_size/2)):(len(time)-int(math.floor(window_size/2)))]
        return bl_time, bl_val

    def baseline_removal(self, signal_time, signal_val, baseline_time, baseline_val):
        signal_time = list(signal_time)
        baseline_time = list(baseline_time)
        blrm_val = signal_val[signal_time.index(baseline_time[0]):signal_time.index(baseline_time[-1])+1] - baseline_val
        return baseline_time, blrm_val

    # Baseline removal followed by zero padding front and back
    def baseline_removal_w_zero_padding(self, signal_time, signal_val, baseline_time, baseline_val):
        signal_time = list(signal_time)
        baseline_time = list(baseline_time)
        blrm_val = signal_val[signal_time.index(baseline_time[0]):signal_time.index(baseline_time[-1])+1] - baseline_val
        output1 = np.pad(blrm_val, (555, 555), 'constant', constant_values=0)  # 0 padding for KT, padding
        # 720 for data length of 40s to get
        # exactly 1 result and no need to take median
        # 555 for data length of 60s
        blrm_val = output1
        time_end = max(baseline_time)
        time_ramp = baseline_time[-1] - baseline_time[-2]
        for i in range(2000):
            append_val = time_end + (i + 1) * time_ramp
            baseline_time = np.append(baseline_time, append_val)   # 0 padding for RR calculation
        return baseline_time, blrm_val

    def artifact(self, time, val, window_size, mva_filt=True):
        output = val[1:len(val)-1]**2 - val[0:len(val)-2] * val[2:len(val)]
        time = time[1:len(val)-1]

        output = np.abs(output)
        if mva_filt == True:  # smoothen the output (optional)
            time, output = self.moving_average(time, output, window_size)
        return time, output

    def artifact_removal(self, signal_time, signal_val, art_time, art_val, artbl_time, artbl_val, th, window_size, mva_filt=True):
        signal_time = list(signal_time)
        art_time = list(art_time)

        signal_val = signal_val[signal_time.index(artbl_time[0]):signal_time.index(artbl_time[-1])+1]
        art_val = art_val[art_time.index(artbl_time[0]):art_time.index(artbl_time[-1])+1]

        output = signal_val[art_val < th*artbl_val]
        if mva_filt == True:  # smoothen the output (optional)
            time = np.arange(0, len(output))
            _, output = self.moving_average(time, output, window_size)
        return output

    def run_signal_processing(self):
        """
        perform signal processing
        """
        self.mva_time,  self.mva_val = self.moving_average(self.time, self.val, self.window_mva)
        self.bl_time,   self.bl_val = self.baseline(self.mva_time, self.mva_val, self.window_bl)
        self.blrm_time, self.blrm_val = self.baseline_removal(self.mva_time, self.mva_val, self.bl_time, self.bl_val)
        self.art_time,   self.art_val = self.artifact(self.blrm_time, self.blrm_val, self.window_art_mva)
        self.artbl_time, self.artbl_val = self.baseline(self.art_time, self.art_val, self.window_art_bl)

    def run_signal_processing_2(self):
        """
        perform signal processing
        """
        self.mva_time,  self.mva_val = self.moving_average(self.time, self.val, self.window_mva)
        self.bl_time,   self.bl_val = self.baseline(self.mva_time, self.mva_val, self.window_bl)
        self.blrm_time, self.blrm_val = self.baseline_removal_w_zero_padding(
            self.mva_time, self.mva_val, self.bl_time, self.bl_val)
        self.art_time,   self.art_val = self.artifact(self.blrm_time, self.blrm_val, self.window_art_mva)
        self.artbl_time, self.artbl_val = self.baseline(self.art_time, self.art_val, self.window_art_bl)

    def run_signal_processing_activity(self):
        """
        perform signal processing
        """
        self.mva_time,  self.mva_val = self.moving_average(self.time, self.val, self.window_mva)
        # print('Window size of the mva for activeness calculation: ', self.window_mva)
        # print(len(self.mva_time), len(self.mva_val))
        self.art_time,   self.art_val = self.artifact(
            self.mva_time, self.mva_val, self.window_art_mva)  # baseline not removed in this algorithm

    def remove_baseline(self):
        self.mva_time,  self.mva_val = self.moving_average(self.time, self.val, self.window_mva)
        self.bl_time,   self.bl_val = self.baseline(self.mva_time, self.mva_val, self.window_bl)
        self.blrm_time, self.blrm_val = self.baseline_removal(self.mva_time, self.mva_val, self.bl_time, self.bl_val)

    def motion_removal2(self, signal, nonactive_time):
        signal_time = list(signal[:, 0])
        signal_val = list(signal[:, 1])
        signal = pd.DataFrame(signal, columns=['timestamp', 'signal'])
        signal['timestamp'].astype(int)
        signal = signal.set_index('timestamp')
        # print(len(signal['signal']))
        nonactive_time = list(nonactive_time)
        nonactive_time = [int(x) for x in nonactive_time]
        nonactive_time_filter1 = list(filter(lambda time: time >= signal_time[0], nonactive_time))
        nonactive_time_filter2 = list(filter(lambda time: time <= signal_time[-1], nonactive_time_filter1))
        # print('Starting and ending point of nonactive time', nonactive_time[0], nonactive_time[-1])
        # print('Starting and ending point of signal index: ', signal.index[0], signal.index[-1])
        # nonactive_signal = signal.iloc[nonactive_time]
        # print('The length of nonactive time and signal', len(nonactive_time_filter2), len(signal))
        nonactive_signal = signal.loc[nonactive_time_filter2]
        nonactive_signal = list(nonactive_signal['signal'])
        # print('The length of the nonactive signal is: ', len(nonactive_signal))
        return nonactive_time_filter2, nonactive_signal



class DetectSensorOnskin():
    def __init__(self, val, dashboard_mode):  # TODO allow to modify params
        if dashboard_mode == 'HR':  # finger sensor
            self.is_ppg = True
            params_onoffskin = {
                "threshold": 3.3,
                "window_size": 750,
                "window_shift": 750,
                "freq_lim": 5,
                "bandpass_lower_lim": 0,
                "bandpass_higher_lim": 5,
                "signal_stdev_threshold": [1, 20],
                "threshold_2lightsources_median": 20,
            }

            prepro_params = {  # TODO clean up params that is not needed
                'sampling_time': 0.04,  # second
                'window_mva': 21,
                'window_bl': 250,
                'window_art_mva': 187,
                'window_art_bl': 750,
                'window_smooth_output': 13,  # smoothen output after artifact removal
                'th_prepro': 2,  # coefficient for artifact removal
                'lag': 2,
                'coef_A': 1.2,
                'coef_B': 0.12,
                'val_min': 1.5,
                'val_max': 10,
                # 'window_size': 1500,
                # 'window_shift': 25,
            }

        elif dashboard_mode == 'RR':  # chest sensor
            self.is_ppg = False
            params_onoffskin = {
                "threshold": 3,
                "window_size": 500,
                "window_shift": 250,
                "freq_lim": 2,
                "bandpass_lower_lim": 0.18,
                "bandpass_higher_lim": 0.68,
                "signal_stdev_threshold": [1, 20],
            }

            prepro_params = {  # TODO clean up params that is not needed
                'sampling_time': 0.06,  # second
                'window_mva': 15,
                'window_bl': 250,
                'window_art_mva': 83,
                'window_art_bl': 666,
                'window_smooth_output': 9,  # smoothen output after artifact removal
                'th_prepro': 3,  # coefficient for artifact removal
                'lag': 2,
                'coef_A': 1.2,
                'coef_B': 0.08,
                'val_min': 1.5,
                'val_max': 15,
                # 'window_size': 1083,
                # 'window_shift': 17,
            }

        self.freq_lim = params_onoffskin['freq_lim']
        self.window_size = params_onoffskin['window_size']
        self.window_shift = params_onoffskin['window_shift']
        self.threshold_onoff_skin = params_onoffskin['threshold']
        self.bandpass_lower_lim = params_onoffskin['bandpass_lower_lim']
        self.bandpass_higher_lim = params_onoffskin['bandpass_higher_lim']
        self.signal_stdev_threshold = params_onoffskin["signal_stdev_threshold"]

        self.val = val
        self.prepro_params = prepro_params
        self.T = prepro_params['sampling_time']
        self.fs = 1/self.T

    def run_fft(self, Xin, fs, n_fft=2**12):  # TODO remove this and have it as utils
        Xin = Xin*np.hanning(len(Xin))
        yf = scipy.fftpack.fft(Xin, n=n_fft)
        N = int(len(yf)/2+1)
        signal_fft = np.abs(yf[0:N])
        signal_fft = signal_fft*signal_fft
        signal_fft = self.minmaxscale(signal_fft)
        x_freq = np.linspace(0, fs/2, N)
        return x_freq, signal_fft

    def minmaxscale(self, x):
        min_val = np.min(x)
        max_val = np.max(x)
        y = [(x[i]-min_val) / (max_val-min_val) for i in range(len(x))]
        return np.array(y)

    def modified_fft(self, Xin, fs, n_fft=2**12, phase=False):
        Xin = Xin*np.hanning(len(Xin))
        yf = scipy.fftpack.fft(Xin, n=n_fft)
        yf = scipy.fftpack.fftshift(yf)
        N = len(yf)

        signal_fft = np.abs(yf)
        signal_fft = signal_fft*signal_fft
        signal_fft = self.minmaxscale(signal_fft)
        x_freq = np.linspace(-fs/2, fs/2, N)
        if phase == False:
            return x_freq, signal_fft
        else:
            p = np.angle(yf)
            # p = p[0:N]
            # p = np.unwrap(p)
            return x_freq, signal_fft, p/np.pi

    def calculate_phase_diff(self, y, fs):
        y = y - np.mean(y)
        freq, mag, p = self.modified_fft(y, fs, phase=True)
        peaks_fft, _ = find_peaks(mag, height=0.001)

        if len(peaks_fft) == 0:
            peak_phase = []
        else:
            sorted_mag_peaks = sorted(mag[peaks_fft], reverse=True)
            phase_idx = np.where(mag == sorted_mag_peaks[0])
            peak_phase = p[phase_idx]

        if len(peak_phase) == 2:
            phase_diff = np.abs(peak_phase[0] - peak_phase[1])
        else:
            phase_diff = 0
        return phase_diff

    def calculate_peak_ratio(self, y, fs, freq_lim, is_ppg, threshold_onoff_skin, bandpass_lower_lim, bandpass_higher_lim):
        y = y - np.mean(y)
        freq, mag = self.run_fft(y, fs)
        freq = freq[np.where(freq <= freq_lim)]
        mag = mag[:len(freq)]

        idx_higher = np.where(freq <= bandpass_higher_lim)
        freq = freq[idx_higher]
        idx_h = [x for xs in idx_higher for x in xs]
        idx_lower = np.where(freq >= bandpass_lower_lim)
        freq = freq[idx_lower]
        idx_l = [x for xs in idx_lower for x in xs]
        mag = mag[idx_l[0]:idx_h[-1]+1]

        peaks_fft, _ = find_peaks(mag, height=0.001)
        sorted_mag_peaks = sorted(mag[peaks_fft], reverse=True)
        if len(sorted_mag_peaks) >= 2:
            peak_ratio = sorted_mag_peaks[0]/sorted_mag_peaks[1]
            peak_ratio = np.clip(peak_ratio, 0, 1000)
        elif len(sorted_mag_peaks) == 1:
            peak_ratio = math.inf
        else:
            peak_ratio = 1

        if is_ppg:
            if (peak_ratio <= threshold_onoff_skin) | (peak_ratio == math.inf):
                sensor_status = 0  # 'off-skin'
            else:
                sensor_status = 1  # 'on-skin'
        else:
            if (peak_ratio <= threshold_onoff_skin) | (peak_ratio == math.inf):
                sensor_status = 0  # 'off-skin'
            else:
                sensor_status = 1  # 'on-skin'

        return sensor_status, peak_ratio

    def determine_onskin(self, list_onskin):

        if len(list_onskin) > 1:
            if sum(list_onskin) >= math.ceil(len(list_onskin)/2):
                output = 1
            else:
                output = 0
        else:
            output = list_onskin[0]
        return int(output)

    def run_calculation(self):

        prepro_signal = signal_processing(self.val, self.prepro_params)  # input to signal processing
        prepro_signal.remove_baseline()

        y = prepro_signal.blrm_val

        self.list_output_peakratio = []
        self.list_onskin_status = []
        self.list_phase_diff = []

        for i in range(0, len(y), self.window_shift):

            temp_window = y[i:i+self.window_size]

            sensor_status, peak_ratio = self.calculate_peak_ratio(
                temp_window, self.fs, self.freq_lim, self.is_ppg, self.threshold_onoff_skin, self.bandpass_lower_lim, self.bandpass_higher_lim)

            temp_phase_diff = self.calculate_phase_diff(temp_window, self.fs)

            self.list_output_peakratio = np.append(self.list_output_peakratio, peak_ratio)
            self.list_onskin_status = np.append(self.list_onskin_status, sensor_status)
            self.list_phase_diff = np.append(self.list_phase_diff, temp_phase_diff)

        self.onskin_status = self.determine_onskin(self.list_onskin_status)
        return

    def run_calculation_2(self):
        prepro_signal = signal_processing(self.val, self.prepro_params)
        bl_time, bl_val = prepro_signal.baseline(prepro_signal.time, prepro_signal.val, prepro_signal.window_bl)
        baseline_time, blrm_val = prepro_signal.baseline_removal(prepro_signal.time, prepro_signal.val, bl_time, bl_val)

        y = blrm_val

        self.list_output_stdev = []
        self.list_onskin_status_stdev = []

        self.list_output_skewness = []
        self.list_output_kurtosis = []

        for i in range(0, len(y), self.window_shift):

            temp_window = y[i:i+self.window_size]

            if len(temp_window) < self.window_size:
                continue

            temp_stdev = np.std(temp_window)

            temp_skew = scipy.stats.skew(temp_window)
            temp_kurtosis = scipy.stats.kurtosis(temp_window)

            if (temp_stdev <= self.signal_stdev_threshold[0]) | (temp_stdev >= self.signal_stdev_threshold[1]):
                sensor_status = 0
            else:
                sensor_status = 1

            self.list_output_stdev = np.append(self.list_output_stdev, temp_stdev)
            self.list_output_skewness = np.append(self.list_output_skewness, temp_skew)
            self.list_output_kurtosis = np.append(self.list_output_kurtosis, temp_kurtosis)

            self.list_onskin_status_stdev = np.append(self.list_onskin_status_stdev, sensor_status)

        self.onskin_status_stdev = self.determine_onskin(self.list_onskin_status_stdev)

        return

def calculate_activeness(xaccl, yaccl, zaccl, params):
    Xinput, Yinput, Zinput = np.array([np.arange(len(xaccl)), xaccl]).T, np.array(
        [np.arange(len(yaccl)), yaccl]).T, np.array([np.arange(len(zaccl)), zaccl]).T
    threshold_x_01, threshold_y_01, threshold_z_01 = params['threshold_x_01'], params['threshold_y_01'], params['threshold_z_01']
    threshold_x_12, threshold_y_12, threshold_z_12 = params['threshold_x_12'], params['threshold_y_12'], params['threshold_z_12']
    cls_sp_x = SignalProcessing(Xinput, params)
    cls_sp_y = SignalProcessing(Yinput, params)
    cls_sp_z = SignalProcessing(Zinput, params)
    cls_sp_x.run_signal_processing_for_activity()
    cls_sp_y.run_signal_processing_for_activity()
    cls_sp_z.run_signal_processing_for_activity()
    activeness, t_activeness = np.zeros(len(cls_sp_x.art_val)), []
    for i in range(0, len(cls_sp_x.art_val)):
        window_sum_x = cls_sp_x.art_val[i]
        window_sum_y = cls_sp_y.art_val[i]
        window_sum_z = cls_sp_z.art_val[i]
        if ((window_sum_x > threshold_x_01 and window_sum_y > threshold_y_01) or (window_sum_x > threshold_x_01 and window_sum_z > threshold_z_01) or (window_sum_y > threshold_y_01 and window_sum_z > threshold_z_01)):
            activeness[i] = 1
        if ((window_sum_x > threshold_x_12 and window_sum_y > threshold_y_12) or (window_sum_x > threshold_x_12 and window_sum_z > threshold_z_12) or (window_sum_y > threshold_y_12 and window_sum_z > threshold_z_12)):
            activeness[i] = 2
        t_activeness = np.append(t_activeness, cls_sp_x.art_time[i])
    return t_activeness, activeness

def moving_average(time, val, window_size):
    """
    If window_size==0: returns input
    """
    if window_size == 0:
        mva_time = time
        mva_val = val
    else:
        temp = pd.Series(val)
        temp_mva = temp.rolling(window=window_size, center=True).mean()
        mva_val = temp_mva[int(math.floor(window_size/2)):(len(temp)-int(math.floor(window_size/2)))]
        mva_val = np.array(mva_val)

        mva_time = time[int(math.floor(window_size/2)):(len(time)-int(math.floor(window_size/2)))]
    return mva_time, mva_val


class DetectSensorSkinContactUsingMultiSensor:

    def __init__(self):
        self.params_th = {
            "SLIDING_WINDOW_SIZE": 16,
            "WINDOW_SIZE": 1000,
            "ON_OFF_SKIN_ACCL_THRESHOLD": 0.35,
            "ON_OFF_SKIN_OPTICAL_THRESHOLD": 1.5,
            "MINIMUM_DATA_LENGTH_AFTER_MOTION_REMOVAL": 250,
            "MAJORITY_THRESHOLD": 0.5,
            "MINIMUM_DATA_LENGTH_FOR_EVAL": 200,
            "TEMPERATURE_THRESHOLD": 27
        }

        self.params_prepro = {
            'sampling_time': 0.06,
            'window_mva': 15,
            'window_mva_activeness': 25,
            'window_bl': 250,
            'window_art_mva': 83,
            'window_art_bl': 667,
            'window_smooth_output': 9,
            'th_prepro': 3,
            'lag': 10,
            'coef_A': 1.4,
            'coef_B': 0.7,
            'val_min': 1.0,
            'val_max': 30,
            'window_size': 1083,
            'window_shift': 16*1,
            'threshold_x_01': 300,
            'threshold_y_01': 310,
            'threshold_z_01': 1060,
            'threshold_x_12': 1700,
            'threshold_y_12': 2400,
            'threshold_z_12': 1600
        }


    def estimate_sensor_skin_contact(self, data):

        SLIDING_WINDOW_SIZE = self.params_th["SLIDING_WINDOW_SIZE"]
        WINDOW_SIZE = self.params_th["WINDOW_SIZE"]
        ON_OFF_SKIN_ACCL_THRESHOLD = self.params_th["ON_OFF_SKIN_ACCL_THRESHOLD"]
        ON_OFF_SKIN_OPTICAL_THRESHOLD = self.params_th["ON_OFF_SKIN_OPTICAL_THRESHOLD"]
        MINIMUM_DATA_LENGTH_AFTER_MOTION_REMOVAL = self.params_th["MINIMUM_DATA_LENGTH_AFTER_MOTION_REMOVAL"]
        MAJORITY_THRESHOLD = self.params_th["MAJORITY_THRESHOLD"]
        MINIMUM_DATA_LENGTH_FOR_EVAL = self.params_th["MINIMUM_DATA_LENGTH_FOR_EVAL"]
        TEMPERATURE_THRESHOLD = self.params_th["TEMPERATURE_THRESHOLD"]

        params = self.params_prepro

        final_labels_list = []
        for start in range(0, len(data), SLIDING_WINDOW_SIZE):
            end = start + WINDOW_SIZE
            if end > len(data):
                break
            data_window = data[start:end]

            temp = data_window[:,6]
            optical = data_window[:,1]
            optical_signal = np.array([np.arange(len(optical)), optical]).T
            accl_plot = data_window[:,2]
            accl_euclidean = data_window[:,2]
            xaccl = data_window[:,3]
            yaccl = data_window[:,4]
            zaccl = data_window[:,5]

            class_sensor_onskin_algo = DetectSensorOnskin(optical_signal, 'RR')
            class_sensor_onskin_algo.run_calculation_2()
            median_list_output_stdev = np.median(class_sensor_onskin_algo.list_output_stdev)
            if median_list_output_stdev > ON_OFF_SKIN_OPTICAL_THRESHOLD:
                opt_label = 1
            else:
                opt_label = 0
            if max(temp)/10 > TEMPERATURE_THRESHOLD:
                temp_label = 1
            else:
                temp_label = 0
            t_sensor = np.arange(len(optical_signal))
            t_activeness, activeness = calculate_activeness(xaccl, yaccl, zaccl, params)
            t_mva_accl, mva_accl = moving_average(t_sensor, accl_euclidean, params['window_mva'])
            if len(t_activeness) > 2:
                cut_start = int(t_activeness[0])
                cut_end = int(t_activeness[-1]+1)
                t_sensor = t_sensor[cut_start:cut_end]
                accl_euclidean = accl_euclidean[cut_start:cut_end]
                t_mva_accl = t_mva_accl[cut_start:cut_end]
                mva_accl = mva_accl[cut_start:cut_end]
                if 2 in activeness:
                    index_to_remove = np.where(activeness == 2)[0]
                    t_activeness = np.delete(t_activeness, index_to_remove)
                    activeness = np.delete(activeness, index_to_remove)
                    t_sensor = np.delete(t_sensor, index_to_remove)
                    mva_accl = np.delete(mva_accl, index_to_remove)
                    t_mva_accl = np.delete(t_mva_accl, index_to_remove)
                    if len(mva_accl) < MINIMUM_DATA_LENGTH_FOR_EVAL:
                        accl_label = 1
                    else:
                        start_chunk = 0
                        std_eval_chunks = []
                        for j in range(1, len(t_mva_accl)):
                            if t_mva_accl[j] - t_mva_accl[j-1] != 1:
                                chunk_to_eval = mva_accl[start_chunk:j]
                                std_eval_chunks.append(np.std(chunk_to_eval))
                                start_chunk = j
                        std_eval_chunks.append(np.std(mva_accl[start_chunk:]))
                        for std in std_eval_chunks:
                            if std > ON_OFF_SKIN_ACCL_THRESHOLD:
                                accl_label = 1
                                break
                            else:
                                accl_label = 0
                else:
                    std_eval = np.std(mva_accl)
                    if std_eval > ON_OFF_SKIN_ACCL_THRESHOLD:
                        accl_label = 1
                    else:
                        accl_label = 0
            else:
                std_eval = np.std(mva_accl)
                if std_eval > ON_OFF_SKIN_ACCL_THRESHOLD:
                    accl_label = 1
                else:
                    accl_label = 0
            if accl_label == 1 and opt_label == 1 and temp_label == 1:
                final_labels_list.append(1)
            else:
                final_labels_list.append(0)
                # print('off skin')
        if len(final_labels_list) == 0:
            final_label = 0
        else:
            average_list = sum(final_labels_list)/len(final_labels_list)
            if average_list >= MAJORITY_THRESHOLD:
                final_label = 1
            else:
                final_label = 0
        # print(final_label)
        debug = {
            "accl_label": accl_label, 
            "opt_label": opt_label,
            "temp_label": temp_label
        }
        return final_label, debug





