    def determine_skin_contact_using_threshold(self, value=None, threshold=None):
        if value is None:
            # value = np.median(self.features["list_diff_ld_med"])
            value = self.features["ld_diff_med"]

        if threshold is None:
            threshold = self.params["threshold"]

        if np.isnan(value):
            return -1  # unknown
        else:
            if value > threshold:
                return 1  # on skin
            else:
                return 0  # off skin

    def determine_skin_contact_using_lda(self, X=None):

        cols = [
        'ld_diff_sd', 'ld2_sd', 'ld1_sd','ld_corr', 'ld1_corr', 'ld2_corr', 'ld1_skewness', 'ld1_kurtosis', 'ld2_skewness', 'ld2_kurtosis',
        'ppgq_snr_ir_db', 'ppgq_snr_red_db', 'ppgq_std_logR', 'ppgq_obf', 'ppgq_coh_fp', 'ppgq_corr_red_ir'
    ]

        # 15s 
        w = np.array([  0.89541194,   0.28171953,  -0.44291456, -15.09296291,
            -6.79127179,   5.46876969,  -0.09940187,  -0.85258364,
            0.07779556,  -0.08825292,   0.81924278,   0.40021036,
        -17.2278068 ,  -4.51558272,  -4.02002032,  31.32724173])
        b = -2.412944512226586
        lda_threshold = 0 # 0


        if X is None:
            X = []
            for key in cols:
                X = np.append(X, self.features[key])

        try:
            z = np.dot(X, w) + b
            y_pred_manual = 1 if z >= lda_threshold else 0
        except Exception as e:
            print(f"unable to execute dot product: {e}")
            y_pred_manual = None

        return y_pred_manual


    def extract_ppg_quality_features(self, ld1, ld2):
        ppg_sqa = assess_ppg_quality(
            red=4096 - np.array(ld1), ir=4096 - np.array(ld2), return_dict=True
        )

        features = {}
        for k, v in ppg_sqa.items():
            # self.features[f"ppgq_{k}"] = v
            features[f"ppgq_{k}"] = v
        
        return features


    def extract_pd_features(self, ld1, ld2):

        SignalPreProcessing = PreProcessing()  # input to signal processing

        _, val_ld1 = SignalPreProcessing.moving_average_filter(
            np.arange(len(ld1)), ld1, self.params["window_mva"]
        )
        _, val_ld2 = SignalPreProcessing.moving_average_filter(
            np.arange(len(ld2)), ld2, self.params["window_mva"]
        )

        sawtooth_template = generate_sawtooth_template(
            self.params["window_size"], frequency=1, amplitude=1, sampling_rate=25
        )

        ld_diff = np.abs(val_ld1 - val_ld2)

        ld_diff_mean = np.mean(ld_diff)
        ld_diff_med = np.median(ld_diff)
        ld_diff_sd = np.std(ld_diff)
        ld_diff_cv = ((ld_diff_sd / ld_diff_mean) * 100)

        ld1_min = (np.min(val_ld1 - np.mean(val_ld1)))
        ld1_max = (np.max(val_ld1 - np.mean(val_ld1)))
        ld1_min_to_max = ld1_min / ld1_max
        ld1_p2p = (ld1_max - ld1_min) / ld1_max

        ld2_min = (np.min(val_ld2 - np.mean(val_ld2)))
        ld2_max = (np.max(val_ld2 - np.mean(val_ld2)))
        ld2_min_to_max = ld2_min / ld2_max
        ld2_p2p = ((ld2_max - ld2_min) / ld2_max)

        ld1_sd = np.std(val_ld1)
        ld1_mean = np.mean(val_ld1)
        ld1_cv = ((ld1_sd / ld1_mean) * 100)

        ld2_sd = np.std(val_ld2)
        ld2_mean = np.mean(val_ld2)
        ld2_cv = ((ld2_sd / ld2_mean) * 100)

        ld_corr = compute_correlation(val_ld1.reshape(-1), val_ld2.reshape(-1))
        ld1_corr = compute_correlation(sawtooth_template, val_ld1.reshape(-1))
        ld2_corr = compute_correlation(sawtooth_template, val_ld2.reshape(-1))

        ld1_skewness = float(_scipy_skew(val_ld1, bias=False, nan_policy="omit"))
        ld1_kurtosis = float(_scipy_kurtosis(val_ld1, fisher=True, bias=False, nan_policy="omit"))
        
        ld2_skewness = float(_scipy_skew(val_ld2, bias=False, nan_policy="omit"))
        ld2_kurtosis = float(_scipy_kurtosis(val_ld2, fisher=True, bias=False, nan_policy="omit"))
        

        features = {
            "ld_diff_mean": ld_diff_mean,
            "ld_diff_med": ld_diff_med,
            "ld_diff_sd": ld_diff_sd,
            "ld_diff_cv": ld_diff_cv,
            "ld1_min": ld1_min,
            "ld1_max": ld1_max,
            "ld1_min_to_max": ld1_min_to_max,
            "ld1_p2p": ld1_p2p,
            "ld2_min": ld2_min,
            "ld2_max": ld2_max,
            "ld2_min_to_max": ld2_min_to_max,
            "ld2_p2p": ld2_p2p,
            "ld1_sd": ld1_sd,
            "ld1_mean": ld1_mean,
            "ld1_cv": ld1_cv,
            "ld2_sd": ld2_sd,
            "ld2_mean": ld2_mean,
            "ld2_cv": ld2_cv,
            "ld_corr": ld_corr,
            "ld1_corr": ld1_corr,
            "ld2_corr": ld2_corr,
            "ld1_skewness": ld1_skewness,
            "ld1_kurtosis": ld1_kurtosis,
            "ld2_skewness": ld2_skewness,
            "ld2_kurtosis": ld2_kurtosis,
        }

        return features


    def extract_features_and_skin_contact(self, ld1, ld2, method="lda", n_consec=10):
        
        window_size = self.params["window_size"] + self.params["window_mva"] - 1
        window_shift = self.params["window_shift"] # 25 # shift every 25 samples
        # window_shift = int(window_size / 2)

        list_skin_contact = []
        features_dict = {}

        for window_ld1, window_ld2 in sliding_window_multi(
            window_size, 
            window_shift,
            np.array(list(ld1)).reshape(-1, 1),
            np.array(list(ld2)).reshape(-1, 1),
        ):
            
            features_pd = self.extract_pd_features(window_ld1.flatten(), window_ld2.flatten())
            features_ppgq = self.extract_ppg_quality_features(window_ld1, window_ld2)
            
            features = {**features_pd, **features_ppgq}
            
            # Initialize lists for each key on first iteration
            if not features_dict:
                for key in features.keys():
                    features_dict[key] = []
            
            # Append each feature value to its corresponding list
            for key, value in features.items():
                features_dict[key].append(value)
            
            self.features = features
            
            if method == "lda":
                temp_skin_contact = self.determine_skin_contact_using_lda()
            elif method == "ppg_sqa":
                temp_skin_contact = self.determin_skin_contact_using_ppg_quality()

            list_skin_contact.append(temp_skin_contact)
        

        consec_found = has_n_consecutive(list_skin_contact, n=n_consec, target=1)

        skin_contact = 1 if consec_found else 0

        # if sum(list_skin_contact) > threshold:
        #     skin_contact = 1
        # else:
        #     skin_contact = 0
        
        return skin_contact, list_skin_contact, features_dict
    
    def determin_skin_contact_using_spo2_frame(self, x, threshold=5):
        return 1 if x >= threshold else 0

    def determin_skin_contact_using_multiple_input(slef, x: list, w: list, threshold: float=3.0):
        val = np.dot(x, w)
        return 1 if val >= threshold else 0

